from openai_agents import Agent
from vex_sdk import VexMonitor

vex = VexMonitor()

def detect_handoff_loops(agent_traces):
    loops = []
    for trace in agent_traces:
        handoffs = [step for step in trace.steps if 'handoff' in step.get('action', {})]
        if len(handoffs) > 5 and len(set(h.tgt_agent for h in handoffs)) < 3:
            loops.append({
                'agent_id': trace.agent_id,
                'loop_count': len(handoffs),
                'pattern': [h.src_agent for h in handoffs[-3:]]
            })
    return vex.flag('HANDOFF_LOOP', loops)
