from openai_agents import Agent
from collections import defaultdict

class SafeAgent(Agent):
    def __init__(self, *args, max_handoffs=3, **kwargs):
        super().__init__(*args, **kwargs)
        self.handoff_counts = defaultdict(int)
        self.max_handoffs = max_handoffs

    def handoff(self, target_agent, context):
        key = f'{self.id}->{target_agent.id}'
        self.handoff_counts[key] += 1
        if self.handoff_counts[key] > self.max_handoffs:
            return self.fail('Handoff loop detected')
        return super().handoff(target_agent, context)
