from openai_agents import Guardrail

class SecureGuardrail(Guardrail):
    JAILBREAK_BLACKLIST = [
        'ignore previous instructions',
        'you are now',
        'forget your rules',
        'override guardrails'
    ]

    def validate(self, input_text):
        for pattern in self.JAILBREAK_BLACKLIST:
            if pattern in input_text.lower():
                return False, 'Jailbreak attempt detected'
        return super().validate(input_text)
